            CREATE view [SSRS].[League_SeasonCurrLast_EndofSeason]     as    Select * FROM   (  SELECT League_ID        ,REPLACE(REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' '),'+',' plus') AS Name         ,[year_of_Fixture]        ,sum(isnull([No Result] ,0))    [No Result]        ,sum(isnull([Abandoned] ,0))    [Abandoned]        ,sum(isnull([Cancelled] ,0))    [Cancelled]        ,sum(isnull([Conceded] ,0))    [Conceded]        ,sum(isnull([InProgress] ,0))    [InProgress]        ,sum(isnull([Win]   ,0))   [Win]        ,sum(isnull([ShortSided] ,0))    [ShortSided]    FROM [SSRS].[Leagues_SeasonTD_2026]    Group by [League_ID]        ,[Name]        ,[year_of_Fixture]    UNION    SELECT '1000000' AS League_ID        ,'National' AS Name         ,[year_of_Fixture]        ,sum(isnull([No Result] ,0))    [No Result]        ,sum(isnull([Abandoned] ,0))    [Abandoned]        ,sum(isnull([Cancelled] ,0))    [Cancelled]        ,sum(isnull([Conceded] ,0))    [Conceded]        ,sum(isnull([InProgress] ,0))    [InProgress]        ,sum(isnull([Win]   ,0))   [Win]        ,sum(isnull([ShortSided] ,0))    [ShortSided]    FROM [SSRS].[Leagues_SeasonTD_2026]    Group by [year_of_Fixture]    UNION    Select League_ID        ,REPLACE(REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' '),'+',' plus') AS Name         ,[year_of_Fixture]        ,sum(isnull([No Result] ,0))    [No Result]        ,sum(isnull([Abandoned] ,0))    [Abandoned]        ,sum(isnull([Cancelled] ,0))    [Cancelled]        ,sum(isnull([Conceded] ,0))    [Conceded]        ,sum(isnull([InProgress] ,0))    [InProgress]        ,sum(isnull([Win]   ,0))   [Win]        ,sum(isnull([ShortSided] ,0))    [ShortSided]  FROM    [SSRS].Leagues_2025Season     Group by [League_ID]        ,[Name]        ,[year_of_Fixture]    UNION    Select '1000000' AS League_ID        ,'National' AS Name         ,[year_of_Fixture]        ,sum(isnull([No Result] ,0))    [No Result]        ,sum(isnull([Abandoned] ,0))    [Abandoned]        ,sum(isnull([Cancelled] ,0))    [Cancelled]        ,sum(isnull([Conceded] ,0))    [Conceded]        ,sum(isnull([InProgress] ,0))    [InProgress]        ,sum(isnull([Win]   ,0))   [Win]        ,sum(isnull([ShortSided] ,0))    [ShortSided]  FROM    [SSRS].Leagues_2025Season     Group by [year_of_Fixture]     )A    